@pytest.mark.parametrize("model_cls, payload", MODEL_CASES)
def test_generated_model_roundtrip(
    model_cls: type[StoneXModel],
    payload: dict[str, object],
) -> None:
    model = model_cls(**payload)
    dumped = model.model_dump(by_alias=True)
    round_tripped = model_cls.model_validate(dumped)
    assert round_tripped.model_dump(by_alias=True) == dumped
